mapper.select:
SELECT p.*, c.name as category_name
FROM product p
LEFT JOIN category c ON p.cat_id = c.id


        AND p.cat_id = #{categoryId}


        AND (p.name LIKE CONCAT('%', #{keyword}, '%')
        OR p.descp LIKE CONCAT('%', #{keyword}, '%'))


        AND p.price >= #{minPrice}


        AND p.price <= #{maxPrice}


ORDER BY p.id DESC
